    // newSum = currentSum + nums[i] = segmentSum(nums, cs, i) + nums[i] = segmentSum(nums, cs, i+1)
    assert newSum == segmentSum(nums, cs, i) + nums[i];
    assert segmentSum(nums, cs, i + 1) == segmentSum(nums, cs, i) + nums[i];
  } else {
    // newSum = nums[i] = segmentSum(nums, i, i+1)
    assert newSum == nums[i];
    assert segmentSum(nums, i, i + 1) == nums[i];
